INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00267', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法第48條第1項受刑人禁用酒類、檳榔但未禁菸，有關受刑人菸酒、檳榔管理等敘述，下 列何者正確？', '["酒類、檳榔屬於娛樂性消耗品，在監獄行刑法第六章「教化及文康」中，基於衛生保健及戒護管理 考量，予以剝奪使用自由", "有限度開放吸菸有助穩定囚情、抒發情緒", "機關對收容人不吸菸及戒菸紀錄，每6個月考評一次並得使用科技設備輔助之", "不吸菸及戒菸之受刑人，監獄得給予增給當月成績總分、增加接見或通信次數或發給獎勵金等方式 予以獎勵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00268', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人在監罹患疾病，有關對於受刑人疾病醫療之處置規定，下列敘述何者錯誤？', '["受刑人罹患疾病，拒不就醫，致有生命危險之虞，監獄得依申請將受刑人逕送醫療機構治療", "罹患疾病之受刑人接受全民健康保險提供之醫療服務或經監獄委請之醫師醫治後，有正當理由認需 由其他醫師診治，而請求自費於監獄內延醫診治時，監獄得予准許", "受刑人罹患疾病，有醫療急迫情形，或經醫師診治後認有必要，監獄得戒送醫療機構或病監醫治", "依監獄行刑法第63條之規定，保外醫治"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00269', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第65條，監獄對於受刑人實施強制營養或醫療之要件，下列敘述何者錯誤？', '["受刑人有拒絕飲食或未依醫囑服藥之行為", "有危及生命之虞的情狀時", "監獄應即請醫師進行診療", "既曰強制營養或醫療，則應由醫師或護理師施以強制營養或採取醫療上必要之強制措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00270', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第76條第3項「監獄代為保管之金錢，除酌留一定金額作為週轉金外，應設專戶管理。」 其所定週轉金保留額度，有關提列基準及其最高金額（以新臺幣計）等敘述，下列何者錯誤？', '["收容人數2000人以上未滿3000人者，80萬元", "收容人數4000人以上未滿5000人者，100萬元", "收容人數5000人以上者，120萬元", "監獄必要時，得報經監督機關核准後，不受法定原則提列週轉金最高金額之限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00271', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["受刑人入監後，以分配於單人舍房為原則，以利安全管理、並維護個人隱私", "監獄受刑人人數嚴重超額時，監督機關視各監獄收容之實際狀況，必要時得機動調整移監", "受刑人有特殊且必要之處遇需求，而本監無法提供相應之資源，監獄得報請監督機關核准移送指定 之監獄", "受刑人對於其他受刑人有顯著之不良影響，有離開本監之必要，監獄得報請監督機關核准移送指定 之監獄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00272', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["適用累進處遇之受刑人甲，生產已滿二月，身體並無不適，監獄仍得給予甲和緩處遇，讓甲得以善 盡母職", "適用累進處遇之受刑人乙，患有疾病經醫師證明需長期療養，監獄得給予乙和緩處遇", "有客觀事實足認適用累進處遇之受刑人丙的身心狀況欠缺辨識能力，致不能處理自己事務，監獄得 給予丙和緩處遇", "適用累進處遇之受刑人丁衰老合併身心障礙、行動不便，且不能自理生活，監獄得給予丁和緩處遇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00273', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["監獄應嚴密戒護，並得運用科技設備輔助之", "監獄認有必要時，得對受刑人居住之舍房及其他處所實施搜檢", "監獄為維護安全，得檢查出入者之衣類及攜帶物品", "戒護、搜檢及檢查，係為維護監獄之安全，不受比例原則之拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00274', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["受刑人有危害監獄安全之虞者，監獄得施以隔離保護", "受刑人之安全有受到危害之虞者，監獄得施以隔離保護", "隔離保護應經監獄長官核准。但情況緊急時，得先行為之，並立即報告監獄長官", "監獄施以隔離保護後，除應以言詞告知受刑人外，應通知其家屬或最近親屬，但不必安排醫事人員 持續評估其身心狀況"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00275', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法相關規定，下列敘述何者錯誤？', '["受刑人有脫逃、自殘、暴行、其他擾亂秩序行為之虞者，監獄得單獨或合併施用戒具、施以固定保 護或收容於保護室", "受刑人有救護必要，非管束不能預防危害者，監獄得單獨或合併施用戒具、施以固定保護或收容於 保護室", "施用戒具、施以固定保護或收容於保護室，監獄不得作為懲罰受刑人之方法。施以固定保護，每次 最長不得逾六小時；收容於保護室，每次最長不得逾四十八小時", "每次施用戒具最長不得逾四十八小時，並應記明起訖時間，但受刑人有暴行或其他擾亂秩序行為致 發生騷動、暴動事故，監獄認為仍有繼續施用之必要者，不在此限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00276', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["受刑人對於他人之生命、身體、自由為強暴、脅迫或有事實足認為將施強暴、脅迫時，監獄人員得 使用法務部核定之棍、刀、槍及其他器械為必要處置", "受刑人持有足供施強暴、脅迫之物，經命其放棄而不遵從時，監獄人員得使用法務部核定之棍、刀、 槍及其他器械為必要處置", "受刑人脫逃，或圖謀脫逃不服制止時，監獄人員得使用法務部核定之棍、刀、槍及其他器械為必要 處置", "監獄人員使用槍械，以維護監所之秩序與安全為限，並得逾必要之程度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
